@using sv_e305a52c201c4cf49e2749f0aef20477.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Security</h4>

@if (_loading)
{
    <div class="spinner-border" role="status"><span class="visually-hidden">Loading...</span></div>
}
else
{
    @if (_message is not null)
    {
        <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <!-- Change Password -->
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center"
             style="cursor: pointer;" @onclick="() => _passwordExpanded = !_passwordExpanded">
            <span><strong>Change Password</strong></span>
            <span>@(_passwordExpanded ? "▲" : "▼")</span>
        </div>
        @if (_passwordExpanded)
        {
            <div class="card-body">
                @if (_settings?.LastPasswordChange.HasValue == true)
                {
                    <p class="text-muted small">Last changed: @_settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
                }

                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="_currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="_newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="_confirmPassword" />
                </div>
                <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                    @if (_changingPassword)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Update Password
                </button>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
                </div>
            </div>
        </div>
    </div>

    <!-- Active Sessions -->
    <div class="card mb-4">
        <div class="card-header"><strong>Active Sessions</strong></div>
        <div class="card-body p-0">
            <table class="table table-hover mb-0">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @if (_settings is not null)
                    {
                        @foreach (var session in _settings.Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (session.Id != _currentSessionId)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-info">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    }
                </tbody>
            </table>
        </div>
    </div>

    <!-- Revoke Confirmation Modal -->
    @if (_sessionToRevoke is not null)
    {
        <div class="modal d-block" tabindex="-1" style="background-color: rgba(0,0,0,0.5);">
            <div class="modal-dialog">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                            @if (_revoking)
                            {
                                <span class="spinner-border spinner-border-sm me-1"></span>
                            }
                            Revoke
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
}

@code {
    private bool _loading = true;
    private SecuritySettings? _settings;
    private bool _twoFactorEnabled;
    private string? _message;
    private bool _messageIsError;

    // Password fields
    private bool _passwordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;

    // Session revocation
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;
    private const string _currentSessionId = "session-1";

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _settings.TwoFactorEnabled;
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "Please fill in all password fields.";
            _messageIsError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _message = "New password and confirmation do not match.";
            _messageIsError = true;
            return;
        }

        _changingPassword = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changingPassword = false;
        _message = "Password updated successfully!";
        _messageIsError = false;
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
        _revoking = false;
        _message = "Session revoked successfully.";
        _messageIsError = false;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
        return $"{(int)diff.TotalDays} days ago";
    }
}

