toolArgs.file_text:
@using sv_e305a52c201c4cf49e2749f0aef20477.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <div class="spinner-border" role="status"><span class="visually-hidden">Loading...</span></div>
}
else
{
    @if (_showSuccess)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            Appearance settings saved!
            <button type="button" class="btn-close" @onclick="() => _showSuccess = false"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-7">
            <!-- Theme -->
            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title">Theme</h6>
                    @foreach (var theme in _themes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <!-- Font Size -->
            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title">Font Size</h6>
                    @foreach (var size in _fontSizes)
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            <!-- Language -->
            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title">Language</h6>
                    <select class="form-select" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <!-- Compact Mode -->
            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <!-- Live Preview -->
        <div class="col-md-5">
            <div class="card sticky-top" style="top: 1rem;">
                <div class="card-header"><strong>Preview</strong></div>
                <div class="card-body @GetPreviewClasses()" style="@GetPreviewStyles()">
                    <h6>Sample Heading</h6>
                    <p>This is how your content will appear with the selected settings.</p>
                    <div class="d-flex gap-2">
                        <button class="btn btn-sm btn-primary">Action</button>
                        <button class="btn btn-sm btn-outline-secondary">Cancel</button>
                    </div>
                    @if (_compactMode)
                    {
                        <p class="mt-2 text-muted small mb-0">Compact mode reduces spacing.</p>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] _themes = { "Light", "Dark", "System" };
    private static readonly string[] _fontSizes = { "Small", "Medium", "Large" };
    private static readonly string[] _languages = { "English", "Spanish", "French", "German", "Japanese", "Chinese" };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_compactMode) classes.Add("p-2");
        else classes.Add("p-3");
        return string.Join(" ", classes);
    }

    private string GetPreviewStyles()
    {
        var styles = new List<string>();

        // Theme
        if (_theme == "Dark")
        {
            styles.Add("background-color: #1a1a2e");
            styles.Add("color: #e0e0e0");
        }
        else
        {
            styles.Add("background-color: #ffffff");
            styles.Add("color: #212529");
        }

        // Font size
        styles.Add(_fontSize switch
        {
            "Small" => "font-size: 0.85rem",
            "Large" => "font-size: 1.15rem",
            _ => "font-size: 1rem"
        });

        // Compact line height
        if (_compactMode)
            styles.Add("line-height: 1.3");

        return string.Join("; ", styles);
    }
}

